import { PageHero, GalleryImage, CTASection } from "@/components/sections";
import galleryKitchen from "@/assets/gallery-kitchen.jpg";
import galleryBedroom from "@/assets/gallery-bedroom.jpg";
import galleryLiving from "@/assets/gallery-living.jpg";
import galleryStairs from "@/assets/gallery-stairs.jpg";
import galleryOffice from "@/assets/gallery-office.jpg";
import galleryEntryway from "@/assets/gallery-entryway.jpg";
import GalleryFilter from "./GalleryFilter";
import { client } from "@/sanity/lib/client";
import { urlForImage } from "@/sanity/lib/image";

export const revalidate = 60; // Revalidate the page every 60 seconds

async function getSanityProjects() {
  const query = `*[_type == "project"] | order(_createdAt desc) {
    _id,
    title,
    city,
    materialType,
    gallery
  }`;
  try {
    const data = await client.fetch(query);
    return data;
  } catch (e) {
    console.error("Error fetching projects from Sanity", e);
    return [];
  }
}

// Fallback images while Sanity is empty
const fallbackImages = [
  { src: galleryLiving, alt: "Modern living room with dark hardwood floors", category: "Hardwood Flooring" },
  { src: galleryKitchen, alt: "Kitchen with light oak flooring", category: "Engineered Flooring" },
  { src: galleryBedroom, alt: "Bedroom with warm hardwood floors", category: "Hardwood Flooring" },
  { src: galleryStairs, alt: "Custom stair treads", category: "Stair Treads" },
  { src: galleryOffice, alt: "Home office with LVP flooring", category: "LVP / LVT / Laminate" },
  { src: galleryEntryway, alt: "Herringbone pattern entryway", category: "Hardwood Flooring" },
  { src: galleryBedroom, alt: "Master bedroom hardwood installation", category: "Soundproof Flooring" },
  { src: galleryLiving, alt: "Open concept living area", category: "LVP / LVT / Laminate" },
  { src: galleryKitchen, alt: "Modern kitchen flooring", category: "Engineered Flooring" },
];

export default async function Gallery() {
  const sanityProjects = await getSanityProjects();

  // Format Sanity images into the expected GalleryImage shape
  let combinedImages: any[] = [];

  if (sanityProjects && sanityProjects.length > 0) {
    sanityProjects.forEach((project: any) => {
      if (project.gallery && project.gallery.length > 0) {
        project.gallery.forEach((imageRef: any, index: number) => {
          const imageUrl = urlForImage(imageRef)?.url();
          if (imageUrl) {
            combinedImages.push({
              src: imageUrl,
              alt: `${project.title} - Image ${index + 1}`,
              category: project.materialType // This is mapped to the new tags
            });
          }
        });
      }
    });
  } else {
    // If no Sanity projects exist yet, use the fallbacks
    combinedImages = fallbackImages;
  }

  return (
    <>
      <PageHero
        title="Our Work"
        description="Browse our portfolio of completed flooring projects across Middle Tennessee. Every project showcases our commitment to quality and craftsmanship."
        breadcrumb="Gallery"
      />

      <section className="section-padding">
        <div className="container-custom">
          <GalleryFilter initialImages={combinedImages} />
        </div>
      </section>

      <CTASection
        title="Love What You See?"
        description="Let's create something beautiful for your home. Request a free quote today."
      />
    </>
  );
}
